#!/usr/bin/env python3
# Generated By: Claude Code (Claude Opus 4.7)
"""Platform-detecting auto-start installer for the AgentPulse service.

Linux  : ~/.config/systemd/user/agentpulse.service + systemctl --user enable --now
Windows: startup-folder .lnk created via PowerShell WScript.Shell COM call
"""

import argparse
import logging
import os
import shutil
import subprocess
import sys
from pathlib import Path

logger = logging.getLogger(__name__)

PROJECT_ROOT = Path(__file__).resolve().parent.parent
TEMPLATES = PROJECT_ROOT / "scripts" / "templates"

# Linux
SYSTEMD_UNIT_NAME = "agentpulse.service"


def _systemd_unit_path() -> Path:
    return Path.home() / ".config" / "systemd" / "user" / SYSTEMD_UNIT_NAME


def _install_linux() -> int:
    template = TEMPLATES / SYSTEMD_UNIT_NAME
    unit_path = _systemd_unit_path()
    unit_path.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(template, unit_path)
    logger.info("installed systemd unit at %s", unit_path)

    subprocess.run(["systemctl", "--user", "daemon-reload"], check=False)
    subprocess.run(
        ["systemctl", "--user", "enable", "--now", SYSTEMD_UNIT_NAME], check=False
    )
    return 0


def _uninstall_linux() -> int:
    subprocess.run(
        ["systemctl", "--user", "disable", "--now", SYSTEMD_UNIT_NAME], check=False
    )
    unit_path = _systemd_unit_path()
    if unit_path.exists():
        unit_path.unlink()
    subprocess.run(["systemctl", "--user", "daemon-reload"], check=False)
    return 0


# Windows
WINDOWS_SHORTCUT_NAME = "AgentPulse.lnk"


def _windows_startup_dir() -> Path:
    appdata = os.environ.get("APPDATA")
    base = Path(appdata) if appdata else Path.home() / "AppData" / "Roaming"
    return base / "Microsoft" / "Windows" / "Start Menu" / "Programs" / "Startup"


def _install_windows() -> int:
    exe = shutil.which("agentpulse") or str(
        Path.home() / ".local" / "bin" / "agentpulse.exe"
    )
    config = Path.home() / ".claude" / "agentpulse" / "config.json"
    startup = _windows_startup_dir()
    startup.mkdir(parents=True, exist_ok=True)
    lnk = startup / WINDOWS_SHORTCUT_NAME

    ps_script = (
        f"$s = (New-Object -ComObject WScript.Shell).CreateShortcut('{lnk}'); "
        f"$s.TargetPath = '{exe}'; "
        f"$s.Arguments = '--config \"{config}\"'; "
        f"$s.WorkingDirectory = '{Path.home()}'; "
        f"$s.Save()"
    )
    result = subprocess.run(
        ["powershell", "-NoProfile", "-Command", ps_script],
        capture_output=True,
        text=True,
    )
    if result.returncode != 0:
        logger.error("powershell failed: %s", result.stderr)
        return result.returncode
    logger.info("installed startup shortcut at %s", lnk)
    return 0


def _uninstall_windows() -> int:
    lnk = _windows_startup_dir() / WINDOWS_SHORTCUT_NAME
    if lnk.exists():
        lnk.unlink()
        logger.info("removed %s", lnk)
    return 0


def install(*, argv: list[str]) -> int:
    argparse.ArgumentParser(prog="install_autostart").parse_args(argv)
    if sys.platform == "linux":
        return _install_linux()
    if sys.platform == "win32":
        return _install_windows()
    print(f"error: unsupported platform: {sys.platform}", file=sys.stderr)
    return 2


def uninstall(*, argv: list[str]) -> int:
    argparse.ArgumentParser(prog="uninstall_autostart").parse_args(argv)
    if sys.platform == "linux":
        return _uninstall_linux()
    if sys.platform == "win32":
        return _uninstall_windows()
    print(f"error: unsupported platform: {sys.platform}", file=sys.stderr)
    return 2


if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO, format="%(message)s")
    action = sys.argv[1] if len(sys.argv) > 1 else "install"
    rest = sys.argv[2:]
    if action == "install":
        sys.exit(install(argv=rest))
    if action == "uninstall":
        sys.exit(uninstall(argv=rest))
    print(f"error: unknown action: {action}", file=sys.stderr)
    sys.exit(2)
